import React, { useState } from 'react'
import Taskcard from './Taskcard'

const Tasks = () => {
  const [taskName, settaskName] = useState('')
  const [tasks, setTasks] = useState([])
  const [subtask, setSubtask] = useState('')
  function handleAdd() {
    if (!taskName.trim()) return;
    const newtask = {
      id: Date.now(),
      title: taskName.trim(),
    };
    setTasks(prev => [...prev, newtask]);
    settaskName('');
  }
  function handleDeleteTask(id) {
  setTasks(prev => prev.filter(task => task.id !== id));
}
  return (
    <div className='task-page'>
        <h1 className="tasks-heading">Tasks</h1>

      <div className='task-header'>
        <div>
          <input className='task-name' placeholder='Enter Task title...' value={taskName} onChange={(e) => settaskName(e.target.value)} />
        </div>
        <div>
          <button className='task-add' onClick={handleAdd}>Add</button>
        </div>
      </div>
      <div className='tasks-list'>
          {tasks.map((task) => {
            return <Taskcard task={task} key={task.id} handleDeleteTask={handleDeleteTask}/>
          })}
      </div>
      <div className='design-layout'>
        <img className='design' src='/assets/background1.png' alt="Design" />
      </div>
      <Stylesheet />
    </div>
  )
}

