const Stylesheet = () => {
  return <style>{`
    .tasks-heading {
      font-size: 2.5rem;
      text-align: center;
      margin-bottom: 1.5rem;
    }

    .task-page {
      padding: 1rem;
      font-family: 'Cedarville Cursive', cursive;
      max-width: 1200px;
      margin: auto;
    }

    
        .design-layout {
            display: flex;
            justify-content: center;
            margin: 2rem 0;
            width: 80%;
            position:absolute;
            bottom:2rem;
        }

        .design {
            width: 80%;
            max-width: 700px;
            height: auto;
            opacity: 0.8;
        }

    .task-header {
      display: flex;
      flex-direction: row;
      align-items: center;
      justify-content: center;
      gap: 1rem;
      flex-wrap: wrap;
      margin-bottom: 2rem;
    }

    .task-name {
      background-color: var(--secondary-color);
      border: none;
      padding: 10px 15px;
      min-width: 250px;
      border-radius: 5px;
      font-size: 1.2rem;
      font-family: 'Cedarville Cursive', cursive;
      color: var(--text);
      flex: 1 1 250px;
    }

    .task-add {
      background-color: var(--button-color);
      border: none;
      padding: 10px 15px;
      min-width: 100px;
      border-radius: 5px;
      font-size: 1.2rem;
      color: var(--bg-parchment);
      font-family: 'Cedarville Cursive', cursive;
      flex-shrink: 0;
    }

    .task-name::placeholder {
      color: var(--text);
      opacity: 1;
    }

    .tasks-list {
      display: flex;
      flex-wrap: wrap;
      justify-content: center;
      gap: 1rem;
      padding: 0 1rem;
    }

    /* Responsive Design */
    @media (max-width: 768px) {
      .task-header {
        flex-direction: column;
        align-items: stretch;
        gap: 0.8rem;
      }

      .task-name,
      .task-add {
        width: 90%;
        font-size: 1rem;
      }

      .tasks-heading {
        font-size: 2rem;
      }
    }

    @media (max-width: 480px) {
      .task-page {
        padding: 0.5rem;
      }

      .tasks-heading {
        font-size: 1.5rem;
      }

      .task-name,
      .task-add {
        font-size: 0.95rem;
      }
    }
  `}</style>
}



export default Tasks
